/**
 * enrich-v3.js - Major content expansion for Book 1 to reach 230+ pages
 * Adds deeper explanations, case studies, practical examples and extended discussions
 * Run: node enrich-v3.js
 */
const fs = require('fs');
const path = require('path');
const bookPath = path.join(__dirname, 'books', 'book-01.json');
const book = JSON.parse(fs.readFileSync(bookPath, 'utf-8'));

function insertAfter(content, headingText, html) {
  const escaped = headingText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`(<h2[^>]*>[^<]*${escaped}[^<]*<\\/h2>)`, 'i');
  if (!regex.test(content)) { console.log('  WARN: heading not found: ' + headingText); return content; }
  return content.replace(regex, `$1${html}`);
}

function appendToChapter(content, html) {
  return content + html;
}

